127→var configSetCmd = &cobra.Command{
128→	Use:   "set <key> <value>",
129→	Short: "Set a CLI preference",
130→	Long: `Set a CLI preference and save it to ~/.sandcastle/config.yaml.
131→
132→Valid keys:
133→  connect_protocol   Connection protocol: "ssh" (default) or "mosh"
134→  use_tmux           Wrap connection in tmux: "true" (default) or "false"
135→  ssh_extra_args     Extra flags appended to the ssh/mosh invocation
136→  mount_home         Mount persistent home on create: "true" or "false" (default)
137→  data_path          Mount user data dir on create: "." (root), subpath, or "off"
138→
139→ENV vars override config file values at runtime:
140→  SANDCASTLE_CONNECT_PROTOCOL, SANDCASTLE_USE_TMUX, SANDCASTLE_SSH_EXTRA_ARGS,
141→  SANDCASTLE_HOME, SANDCASTLE_DATA`,
142→	Args: cobra.ExactArgs(2),
143→	RunE: func(cmd *cobra.Command, args []string) error {
144→		key, value := args[0], args[1]
145→
146→		cfg, err := config.Load()
147→		if err != nil {
148→			return err
149→		}
150→
151→		if err := cfg.SetPreference(key, value); err != nil {
152→			return err
153→		}
154→
155→		if err := config.Save(cfg); err != nil {
156→			return err
157→		}
158→
159→		fmt.Printf("Set %s = %s\n", key, value)
160→		return nil
161→	},
162→}
