164→// Server management commands
165→
166→var serverCmd = &cobra.Command{
167→	Use:   "server",
168→	Short: "Manage configured servers",
169→}
170→
171→var serverListCmd = &cobra.Command{
172→	Use:     "list",
173→	Short:   "List configured servers",
174→	Aliases: []string{"ls"},
175→	RunE: func(cmd *cobra.Command, args []string) error {
176→		cfg, err := config.Load()
177→		if err != nil {
178→			return err
179→		}
180→
181→		if len(cfg.Servers) == 0 {
182→			fmt.Println("No servers configured. Run: sandcastle login <url>")
183→			return nil
184→		}
185→
186→		for alias, srv := range cfg.Servers {
187→			marker := "  "
188→			if alias == cfg.CurrentServer {
189→				marker = "* "
190→			}
191→			tokenStatus := "no token"
192→			if srv.Token != "" {
193→				tokenStatus = "authenticated"
194→			}
195→			fmt.Printf("%s%-12s %s (%s)\n", marker, alias, srv.URL, tokenStatus)
196→		}
197→		return nil
198→	},
199→}
