201→var serverUseCmd = &cobra.Command{
202→	Use:   "use <alias>",
203→	Short: "Set the active server",
204→	Args:  cobra.ExactArgs(1),
205→	RunE: func(cmd *cobra.Command, args []string) error {
206→		alias := args[0]
207→		cfg, err := config.Load()
208→		if err != nil {
209→			return err
210→		}
211→
212→		// Allow using URL as alias — find matching server
213→		if _, ok := cfg.Servers[alias]; !ok {
214→			for a, srv := range cfg.Servers {
215→				if srv.URL == strings.TrimRight(alias, "/") {
216→					alias = a
217→					break
218→				}
219→			}
220→		}
221→
222→		if _, ok := cfg.Servers[alias]; !ok {
223→			return fmt.Errorf("server %q not found — run: sandcastle server list", alias)
224→		}
225→
226→		cfg.CurrentServer = alias
227→		if err := config.Save(cfg); err != nil {
228→			return err
229→		}
230→
231→		fmt.Printf("Switched to %s (%s)\n", alias, cfg.Servers[alias].URL)
232→		return nil
233→	},
234→}
