236→var serverRemoveCmd = &cobra.Command{
237→	Use:     "remove <alias>",
238→	Short:   "Remove a configured server",
239→	Aliases: []string{"rm"},
240→	Args:    cobra.ExactArgs(1),
241→	RunE: func(cmd *cobra.Command, args []string) error {
242→		alias := args[0]
243→		cfg, err := config.Load()
244→		if err != nil {
245→			return err
246→		}
247→
248→		if _, ok := cfg.Servers[alias]; !ok {
249→			return fmt.Errorf("server %q not found", alias)
250→		}
251→
252→		delete(cfg.Servers, alias)
253→		if cfg.CurrentServer == alias {
254→			cfg.CurrentServer = ""
255→			// Set first remaining server as current
256→			for a := range cfg.Servers {
257→				cfg.CurrentServer = a
258→				break
259→			}
260→		}
261→
262→		if err := config.Save(cfg); err != nil {
